pub enum LblView {
    Tau,
    AcquireLock { core: Core },
    ReleaseLock { core: Core },
    InitShootdown { core: Core, vaddr: nat },
    WaitShootdown { core: Core },
    AckShootdown { core: Core },
    Allocate { core: Core, res: MemRegion },
    Deallocate { core: Core, reg: MemRegion },
}

impl View for Lbl {
    type V = LblView;
    closed spec fn view(&self) -> LblView {
        match *self {
            Lbl::Tau => LblView::Tau,
            Lbl::AcquireLock { core } => LblView::AcquireLock { core },
            Lbl::ReleaseLock { core } => LblView::ReleaseLock { core },
            Lbl::InitShootdown { core, vaddr } => LblView::InitShootdown { core, vaddr },
            Lbl::WaitShootdown { core } => LblView::WaitShootdown { core },
            Lbl::AckShootdown { core } => LblView::AckShootdown { core },
            Lbl::Allocate { core, res } => LblView::Allocate { core, res },
            Lbl::Deallocate { core, reg } => LblView::Deallocate { core, reg },
        }
    }
}

